var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>적 전자 시스템 프로토콜 분석 종료. X밴드 전술 통신파 간섭 가능.</color>","JPN":"<color=#ffd34c>敵の電子システムプロトコル分析を終了。Xバンド戦術通信波への干渉可能。</color>","ENG":"<color=#ffd34c>Analysis on the enemy C4I protocols is complete. Jamming of X-band tactical comms is now possible.</color>","TWN":"<color=#ffd34c>敵方電子系統協議分析完畢，可以對X頻段戰術通信波進行干涉。</color>"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>제 2급 시스템 관리자 권한 탈취를 완료했습니다. 명령을.</color>","JPN":"<color=#ffd34c>第2級のシステム管理者権限を奪取完了しました。命令をお願いします。</color>","ENG":"<color=#ffd34c>Class 2 system administrator rights hijacked successfully. Awaiting your command.</color>","TWN":"<color=#ffd34c>成功奪取二級系統管理者權限，請下達命令。</color>"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"좋아!","JPN":"やった！","ENG":"Great!","TWN":"很好！！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"락다운 쇼크 버스터, 기동!","JPN":"ロックダウンショックバスター、起動！","ENG":"Activate lockdown shock buster!","TWN":"封鎖衝擊炸裂，啟動！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"통합 전술 시스템이 작동하지 않습니다!","JPN":"統合戦術システムが作動しません！","ENG":"Our integrated tactical system is down!","TWN":"統合戰術系統無法動作！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"서프레션 프로토콜 기동 실패!","JPN":"サプレッションプロトコルの起動に失敗！","ENG":"Suppression Protocol failed!","TWN":"抑制協定啟動失敗！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"기계화 부대 작동 정지! 시동이 걸리지 않습니다!","JPN":"機械化部隊の作動停止！起動できません！","ENG":"Mechanized units offline! We can’t get them started!","TWN":"機械化部隊停止運作！無法啟動！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"뭐? 이게 다 무슨 일이야?! 당장 원인 파악해!","JPN":"なに？　いったいどういうことだ！？　直ちに原因を調べろ！","ENG":"What? What’s going on?! Track down the cause right away!","TWN":"什麼？所有部隊都發生這種事？！立即找出原因！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"전자 시스템 전체가 강력한 외부 침투형 바이러스에 오염된 것 같습니다!","JPN":"電子システム全体が強力な外部浸透型のウイルスに汚染されたようです！","ENG":"The entire system seems to be compromised by a powerful virus!","TWN":"所有電子系統似乎都遭受了外部滲透型病毒的感染！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"전투 속행 불가!","JPN":"戦闘続行不可！","ENG":"We can’t proceed with the operation like this!","TWN":"無法繼續戰鬥！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"......이런 젠장! 전 부대! 일시 후퇴한다!","JPN":"……くそっ！　全部隊はいったん後退せよ！","ENG":"Damn it... All units! Fall back!","TWN":"……該死！全體部隊！暫時性撤退！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"사격 중지! 놈들이 물러난다.","JPN":"射撃中止！　奴らが下がっている。","ENG":"Cease fire! They’re falling back.","TWN":"停止射擊！那些傢伙撤退了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"끄, 끝난 거야?","JPN":"お、終わったんですか？","ENG":"I-is it over?","TWN":"結、結束了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"일단은.","JPN":"とりあえずはね。","ENG":"For now.","TWN":"暫時是這樣沒錯。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하지만 다시 몰려올 거야. 저건 전초부대일 뿐이니까.","JPN":"でも、またやってくると思う。あれは前哨部隊に過ぎないから。","ENG":"But they’ll be back. They were only the vanguard.","TWN":"但他們還會再殺過來的，那些只是前哨部隊而已。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그보다 대단한데요, 실비아 씨? 마지막에 그건 어떻게 한 거에요?","JPN":"それよりすごいですね、シルビアさん。最後のあれは、どうやったんですか？","ENG":"I’m impressed, Sylvia. How did you pull that off?","TWN":"不過妳好厲害啊，希爾維亞小姐？最後那個怎麼做到的呀？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"상대편 무기들을 모조리 작동 정지시켜 버렸잖아요?","JPN":"相手の武器を全て停止させましたよね？","ENG":"You put their all weapons out of commission!","TWN":"妳讓對方所有的武器都無法運作了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 정도는 별거 아니지. 그냥 잔재주 같은 거야.","JPN":"あれくらい、大したことないわ。ただの小細工に過ぎないから。","ENG":"This is nothing. Child’s play, really.","TWN":"這種事不算什麼，只不過是些小伎倆罷了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"좋아! 중화기가 없으면 저런 약골들 아무것도 아니야. 당장 쳐들어가서 박살을.......","JPN":"よーし！　重火器がなければ、ただの雑魚どもだ。すぐに攻め込んで、撲滅……","ENG":"Great! Without their heavy firearms, those weaklings are nothing. Let’s get in there and crush them-","TWN":"很好！那群弱雞只要沒了重型武器根本就沒什麼。我們馬上殺過去打爆他們……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그건 안 돼. 적들이 원숭이도 아닌데 두 번이나 같은 수에 당할 것 같아?","JPN":"それはダメよ。猿でもあるまいし、同じ手でやられてくれると思う？","ENG":"We can’t do that. These guys aren’t complete idiots. You think they’re going to fall for the same trick twice?","TWN":"不行，敵人又不是猴子，同樣的招數哪會中兩次？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"다음번엔 저 녀석들도 제대로 전자전 방어 준비를 해 올 거야.","JPN":"今度はあいつらも、電子戦防御の対策を立ててくるわ。","ENG":"They’ll come back prepared for electronic warfare next time.","TWN":"他們下次應該會做好電子戰的防禦準備。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐? 잘난 척은 있는 대로 하더니 고작 해킹 한 번 하고 리타이어라는 거냐?!","JPN":"はあ？　偉そうなことばっか言って、ハッキング一回だけでお手上げか！？","ENG":"What? You’re gonna chicken out after your little hacking trick? You cocky nerd!","TWN":"什麼？妳裝得一副很跩的樣子，結果只駭掉他們系統一次就準備退場了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"물론 내가 못 뚫을 보안 시스템 같은 건 없지만, 조금 전처럼 전술 시스템을 통째로 날려버리는 건 힘들어.","JPN":"もちろん、アタシに突破できないセキュリティシステムなんてないけど、さっきのように戦術システムを丸ごと破壊するのは難しいわ。","ENG":"Hey, there’s no system I can’t hack, but throwing off an entire tactical system like that is another story.","TWN":"當然沒有我駭不掉的安全系統，但要像剛才那樣，把他們整個戰術系統都摧毀是很困難的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"제한적으로 간섭할 수는 있겠지만.......","JPN":"一部には干渉はできると思うけど……","ENG":"Although I guess I could still interfere with their comms...","TWN":"雖然能在限定條件下進行干涉……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 그런데 왜 내가 지금 변명을 하고 있는 거지?","JPN":"って、なんでアタシが言い訳しなきゃならないわけ？","ENG":"Hang on, why am I even explaining myself to you?","TWN":"不對，為什麼我在為自己辯解啊？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"넌 뭐 잘한 게 있다고 나불거려?","JPN":"君はいったいどんな役に立ったのかしら？","ENG":"You've got a big mouth for someone who did absolutely nothing to help.","TWN":"妳就好棒棒了？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"딱 봐도 진화가 덜 된 네안데르탈인 같은 게!","JPN":"パッと見、進化できなかったネアンデルタール人みたいな君が！","ENG":"You’re obviously nothing but a primitive Neanderthal!","TWN":"我一看妳，就覺得妳像隻沒有進化的尼安德塔人！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"나 고용주야. 돈 받기 싫어? 관리국에 클레임 좀 걸어 볼까?!","JPN":"アタシは雇い主よ？　お金もらいたくないの？　管理局にクレームでも入れてみましょうか！？","ENG":"Look, I’m the one paying your salary here. You looking to get your pay docked? Or maybe I’ll file a complaint with the Administration!","TWN":"我可是雇主耶，妳是不想賺錢了嗎？是要我去跟管理局投訴嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"음. 충분히 납득 가능한 항의로 판단된다.","JPN":"うん。十分納得できる抗議ね。","ENG":"Hmm... She's got a point, you know.","TWN":"嗯，這個抗議完全可以接受。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야! 멸치! 방금 뭐라고 그랬냐!","JPN":"おい！　イワシ！　今なんて言った！","ENG":"Hey! Weak Sauce! What did you just say?","TWN":"喂！小魚乾！妳剛才說什麼！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시끄러워요, 다들.","JPN":"ずいぶんと騒がしいですね。","ENG":"That's enough, everyone.","TWN":"你們很吵喔，兩位。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자꾸 떠들면 방구석에서 실업급여나 받으며 뒹굴고 싶다는 뜻으로 알아듣겠습니다.","JPN":"これ以上騒いだら、失業して引きこもりたいという意味で捉えます。","ENG":"If I hear another squeak out of you, I’ll consider it your resignation.","TWN":"如果你們再這麼吵的話，我就會以為你們想要拿失業補助金，無所事事地蹲在房間角落。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"출장소는 불타고, 장비도 다 박살나고.......","JPN":"出張所は火事に遭い、装備は全部壊れて……","ENG":"So our field office is literally on fire and all our equipment has been damaged...","TWN":"辦公室都燒掉了，設備也全毀了……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이래서야 손해가 막심하군요.","JPN":"これは甚大な損害ですね。","ENG":"This is going to put us in the red.","TWN":"真是損失慘重啊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하긴, 내 팔자에 무슨 흑자기업 같은 게 있겠어요.","JPN":"まあ、私の人生に黒字企業なんてあるはずありませんね。","ENG":"Then again, of course I’m never going to turn a profit. Not with my luck.","TWN":"也是，我命裡哪有什麼能盈利的公司啊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이제 보니 스타킹 올도 다 나갔네요. 이틀 전에 산 건데....... 후우.","JPN":"今見たら、ストッキングも伝線してるし……2日前に買ったばかりなのに……ふう。","ENG":"Oh, look. There's a run in my tights too. I just got this two days ago... *Sigh*","TWN":"然後現在一看，才發現我的絲襪都破了，我兩天前才剛買的耶……唉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하, 하하....... 부, 부사장님, 혹시 다친 데는 없으세요?","JPN":"あ、あはは……副社長、お怪我はありませんか？","ENG":"Uh... Haha... A-are you otherwise okay, ma’am?","TWN":"哈，哈哈……副、副總，您沒有受傷吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"내일 모레쯤 덮칠 근육통이 좀 끔찍할 것 같긴 하지만......","JPN":"明後日くらいに激しい筋肉痛が襲ってきそうで怖いですが……","ENG":"I’ll probably be sore all over for the next few days...","TWN":"雖然我猜明後兩天的肌肉酸痛應該會很可怕……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 그래도 몸에 구멍 난 곳은 없는 것 같군요.","JPN":"まあ、幸い体に穴は空いていないようですね。","ENG":"But otherwise I’m fairly intact.","TWN":"不過身上並沒有被開洞。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그보다 펜릴 소대에 지원 요청은 보냈나요?","JPN":"それより、フェンリル小隊に支援要請は送りましたか？","ENG":"Anyway, did you call for backup from Fenrir Squad?","TWN":"不說這些了，妳有把支援請求發給芬里爾小隊嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"최초 교전 직후에 바로 보냈습니다.","JPN":"最初の交戦直後に送りました。","ENG":"We did, as soon as we first made contact with the hostiles.","TWN":"我在最初的戰鬥後立刻就通知他們了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"하지만 아시다시피 차원간 통신이라는 게 특별한 경우를 제외하면 확실히 도착한다는 보장이 없어서......","JPN":"ただ、ご存知のとおり、次元間通信は特別な場合を除いて確実に届くという保証がないので……","ENG":"But as you know, there’s no way to guarantee interdimensional transmissions, save for a few special exceptions...","TWN":"但是您也知道，次元間的通信除非特殊情況，無法保證一定能傳達給對方……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그쪽에서 연락을 받았는지는 알 수 없습니다.","JPN":"向こうに届いているかどうかはわかりません。","ENG":"So we can’t confirm if they received our call.","TWN":"所以我不知道那邊有沒有收到聯絡。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다. 그럼 다음은.......","JPN":"わかりました。では、次は……","ENG":"Understood. Alright, then. We should-","TWN":"我知道了。那再來是……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐! 아가씨들! 그쪽 상황은 어때?","JPN":"おい、嬢ちゃんたち！　そっちの状況はどうだ？","ENG":"Hey! Ladies! How's it going over there?","TWN":"喂！小姐們！你們那裡情況怎麼樣啦？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BATTLEFIELD"}]`);export{e as default};